//
// Novel (hand-written) command — not regenerated by the press.
//
// Plane's work-item file-attachment flow is three steps:
//   1. POST .../issues/{id}/issue-attachments/ with {name,type,size}
//      → returns an asset id plus a presigned object-storage POST (upload_data).
//   2. POST the raw file bytes to that storage endpoint (S3/MinIO presigned POST).
//   3. PATCH .../issue-attachments/{asset}/ with {is_uploaded:true} to publish it.
//
// The generated CLI exposes only steps 1 (`issues create-work-item-attachment`)
// and 3 (`issues upload-work-item-attachment`); step 2 is a raw storage POST the
// press cannot model, so a generated CLI alone can describe an attachment but
// never actually upload a file. `attach-file` does all three in one command.

package cli

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"mime"
	"mime/multipart"
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/spf13/cobra"
)

func newAttachFileCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "attach-file <issue_id> <project_id> <file_path>",
		Short: "Attach a local file to a work item (presign → upload → mark uploaded) in one step.",
		Long: `Attach a local file to a Plane work item.

Plane's attachment flow is three round-trips: presign, upload the bytes to object
storage, then mark the attachment uploaded. The generated CLI exposes only the
presign and mark steps; this command performs all three, so a single call puts a
real file on the work item.

Workspace selection follows the global precedence: --workspace > $PLANE_SLUG > the
saved default (plane-pp-cli workspaces use <slug>).`,
		Example: `  plane-pp-cli attach-file \
    17334f5e-9e3f-41e8-ab27-69f68ecc5ce3 \
    8feda17c-6680-4f9d-a485-5cae321cd0cc \
    ./report.pdf`,
		Args: cobra.MaximumNArgs(3),
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) < 3 {
				return usageErr(fmt.Errorf(
					"issue_id, project_id and file_path are required\nUsage: %s <issue_id> <project_id> <file_path>",
					cmd.CommandPath()))
			}
			issueID, projectID, filePath := args[0], args[1], args[2]

			info, err := os.Stat(filePath)
			if err != nil {
				return usageErr(fmt.Errorf("cannot read file %q: %w", filePath, err))
			}
			if info.IsDir() {
				return usageErr(fmt.Errorf("%q is a directory, not a file", filePath))
			}
			name := filepath.Base(filePath)
			size := info.Size()
			if size == 0 {
				return usageErr(fmt.Errorf("%q is empty; storage rejects zero-byte uploads", filePath))
			}
			ctype := mime.TypeByExtension(filepath.Ext(filePath))
			if ctype == "" {
				ctype = "application/octet-stream"
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}
			// newClient() has already resolved the workspace slug through the
			// full precedence chain (--workspace > PLANE_SLUG > default_workspace
			// > sentinel) into the client's TemplateVars. Reuse it rather than a
			// second, weaker resolution, so attach-file honors every workspace
			// source the rest of the CLI does.
			if c.Config == nil || c.Config.TemplateVars["slug"] == "" || c.Config.TemplateVars["slug"] == "my-workspace" {
				return usageErr(fmt.Errorf("workspace not set: pass --workspace <slug>, export %s, or run 'plane-pp-cli workspaces use <slug>'", envWorkspaceSlug))
			}

			// Step 1 — presign. Workspace-relative path; BaseURL + TemplateVars[slug]
			// supply the /api/v1/workspaces/{slug} prefix.
			presignPath := fmt.Sprintf("/projects/%s/issues/%s/issue-attachments/", projectID, issueID)
			raw, _, err := c.Post(cmd.Context(), presignPath, map[string]any{
				"name": name,
				"type": ctype,
				"size": size,
			})
			if err != nil {
				return classifyAPIError(err, flags)
			}
			// --dry-run short-circuits in the client; nothing was uploaded, so
			// surface the planned presign request and stop.
			if flags.dryRun {
				return printOutputWithFlags(cmd.OutOrStdout(), raw, flags)
			}

			var pres struct {
				Attachment struct {
					ID string `json:"id"`
				} `json:"attachment"`
				UploadData struct {
					URL    string            `json:"url"`
					Fields map[string]string `json:"fields"`
				} `json:"upload_data"`
			}
			if err := json.Unmarshal(raw, &pres); err != nil {
				return fmt.Errorf("parsing presign response: %w", err)
			}
			if pres.Attachment.ID == "" || pres.UploadData.URL == "" {
				return fmt.Errorf("presign response missing asset id or upload url: %s", string(raw))
			}

			// Step 2 — upload the bytes to object storage.
			if err := uploadPresignedFile(cmd.Context(), pres.UploadData.URL, pres.UploadData.Fields, filePath, flags.timeout); err != nil {
				return err
			}

			// Step 3 — mark uploaded.
			markPath := fmt.Sprintf("/projects/%s/issues/%s/issue-attachments/%s/", projectID, issueID, pres.Attachment.ID)
			if _, _, err := c.Patch(cmd.Context(), markPath, map[string]any{"is_uploaded": true}); err != nil {
				return classifyAPIError(err, flags)
			}

			result, _ := json.Marshal(map[string]any{
				"success":  true,
				"asset_id": pres.Attachment.ID,
				"name":     name,
				"type":     ctype,
				"size":     size,
				"issue":    issueID,
				"project":  projectID,
			})
			return printOutputWithFlags(cmd.OutOrStdout(), json.RawMessage(result), flags)
		},
	}
	return cmd
}

// uploadPresignedFile performs the object-storage half of an attachment upload:
// an S3/MinIO presigned POST. The presigned form fields must precede the file
// part and the "file" part must be last; no per-part Content-Type is set, since
// the presign policy already pins the stored object's Content-Type (an explicit
// per-part type can break the multipart body — observed as a silent transport
// failure against MinIO).
//
// A timeout (the global --timeout, default 60s) bounds the whole presigned POST
// so a slow or unreachable storage endpoint cannot hang the command
// indefinitely; cmd.Context() still carries user cancellation (Ctrl+C) on top.
func uploadPresignedFile(ctx context.Context, url string, fields map[string]string, filePath string, timeout time.Duration) error {
	f, err := os.Open(filePath)
	if err != nil {
		return fmt.Errorf("opening file for upload: %w", err)
	}
	defer f.Close()

	var buf bytes.Buffer
	w := multipart.NewWriter(&buf)
	for k, v := range fields {
		if err := w.WriteField(k, v); err != nil {
			return fmt.Errorf("writing storage form field %q: %w", k, err)
		}
	}
	part, err := w.CreateFormFile("file", filepath.Base(filePath))
	if err != nil {
		return fmt.Errorf("creating file part: %w", err)
	}
	if _, err := io.Copy(part, f); err != nil {
		return fmt.Errorf("streaming file bytes: %w", err)
	}
	if err := w.Close(); err != nil {
		return fmt.Errorf("finalizing multipart body: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, &buf)
	if err != nil {
		return fmt.Errorf("building storage upload request: %w", err)
	}
	req.Header.Set("Content-Type", w.FormDataContentType())

	httpClient := &http.Client{Timeout: timeout}
	resp, err := httpClient.Do(req)
	if err != nil {
		return fmt.Errorf("uploading to storage: %w", err)
	}
	defer resp.Body.Close()
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		body, _ := io.ReadAll(io.LimitReader(resp.Body, 2048))
		return fmt.Errorf("storage upload failed: HTTP %d: %s", resp.StatusCode, string(body))
	}
	return nil
}
